import React from 'react';
import { Link } from 'react-router-dom';
import './Categories.css';

const CATEGORIES = [
  { name: 'Necklaces', count: '48 items', icon: '📿', bg: '#fff0e6' },
  { name: 'Rings',     count: '64 items', icon: '💍', bg: '#f0e6ff' },
  { name: 'Earrings',  count: '52 items', icon: '✨', bg: '#e6f0ff' },
  { name: 'Bracelets', count: '36 items', icon: '⭕', bg: '#e6fff0' },
];

function Categories() {
  return (
    <section className="categories-section">
      <h2 className="section-title">Shop by Category</h2>
      <div className="gold-divider"></div>
      <p className="section-subtitle">Explore our curated jewellery collections</p>

      <div className="categories-grid">
        {CATEGORIES.map((cat) => (
          <Link to="/shop" key={cat.name} className="category-card">
            <div className="category-img-tile" style={{ background: cat.bg }}>
              <span className="category-tile-icon">{cat.icon}</span>
            </div>
            <div className="category-overlay">
              <span className="category-icon">{cat.icon}</span>
              <span className="category-name">{cat.name}</span>
              <span className="category-count">{cat.count}</span>
            </div>
          </Link>
        ))}
      </div>
    </section>
  );
}

export default Categories;
